const Q_ACCOUNTS_2013=[{"id": "objective>Accounts>2013>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">which subject are you writing now?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Accounts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mathematics </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Yoruba</div>", "<div style=\"font-family:Cambria;font-size:17px;\">French</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The question asks about the subject being written now. Since the subject is mentioned in the question is as 'Accounts', the correct answer is 'Accounts'.</div>", "topic": "INTRODUCTION TO ACCOUNTING : MEANING AND OBJECTIVES OF ACCOUNTING AND BOOKKEEPING"}, {"id": "objective>Accounts>2013>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Accounting information seeks to provide</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">permanent records for all transactions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">analysis of accounts to trade debtors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">audited reports on the accounts of a company </div>", "<div style=\"font-family:Cambria;font-size:17px;\">data about the employees of the company </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The aim of accounting is to provide useful and reliable information about businesses and non-profits. Financial accounting seeks to determine a firm's economic performance and its condition. Accounting records, among other benefits provides permanent records for all transactions.</div>", "topic": "INTRODUCTION TO ACCOUNTING : MEANING AND OBJECTIVES OF ACCOUNTING AND BOOKKEEPING"}, {"id": "objective>Accounts>2013>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When the debit side total of an account exceeds the credit side total while balancing an account, it means that the account has </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">been overdrawn</div>", "<div style=\"font-family:Cambria;font-size:17px;\">been understated </div>", "<div style=\"font-family:Cambria;font-size:17px;\">debit balance </div>", "<div style=\"font-family:Cambria;font-size:17px;\">credit balance </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When the debit side total of an account exceeds the credit side total, it means that the account has a debit balance. In accounting, a debit balance is the ending balance in an account that has more debits than credits. This is traditionally the normal balance for asset accounts, expense accounts, and the owner's drawing account.</div>", "topic": "THE LEDGER : APPLICATION OF DOUBLE ENTRY IN LEDGER"}, {"id": "objective>Accounts>2013>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the information below to answer this question <br/> July 1 - Started business with ₦ 10,500 <br/> July 31 - Paid Agromachinex owing to them ₦6,000 <br/>  <br/> The double entry for July 1 would be </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">debit capital and credit cash </div>", "<div style=\"font-family:Cambria;font-size:17px;\">credit cash and debit bank  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">debit cash and credit capital </div>", "<div style=\"font-family:Cambria;font-size:17px;\">debit purchases and credit cash </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It will be to debit capital and credit cash. Remember the principle of debit the receiver and credit the giver. </div>", "topic": "PRINCIPLE OF DOUBLE ENTRY : CASH AND CREDIT TRANSACTIONS"}, {"id": "objective>Accounts>2013>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the information below to answer this question <br/> July 1 - Started business with ₦ 10,500 <br/> July 31 - Paid Agromachinex owing to them ₦6,000  <br/> The double entry for July 31 would be </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">debit Agromachinex and credit cash </div>", "<div style=\"font-family:Cambria;font-size:17px;\">debit equipment and credit Agromachinex </div>", "<div style=\"font-family:Cambria;font-size:17px;\">credit capital and debit cash </div>", "<div style=\"font-family:Cambria;font-size:17px;\">credit cash debit purchases </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The double entry system of accounting means that every transaction will involve two accounts. In this case, the business is paying a debt it owes to Agromachinex. This means cash (an asset) is decreasing, which is a credit, and the liability (amount owed to Agromachinex) is also decreasing, which is a debit. Therefore, the correct double entry is to debit Agromachinex and credit cash.</div>", "topic": "PRINCIPLE OF DOUBLE ENTRY : CASH AND CREDIT TRANSACTIONS"}, {"id": "objective>Accounts>2013>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The total credit sales for a period can be extracted from the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cash book </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sales day book.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">petty cash book </div>", "<div style=\"font-family:Cambria;font-size:17px;\">return inwards</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It can be seen in the sales day book. The sales day book is a manually-maintained ledger in which is recorded the key detailed information for each individual credit sale to a customer including customer name, invoice number, invoice date. invoice amount.</div>", "topic": "SUBSIDIARY BOOKS : MEANING AND IMPORTANCE"}, {"id": "objective>Accounts>2013>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major source document which enables an employer to calculate the employee wages is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nominal roll of employees </div>", "<div style=\"font-family:Cambria;font-size:17px;\">record of numbers of hours worked </div>", "<div style=\"font-family:Cambria;font-size:17px;\">effort of the employee</div>", "<div style=\"font-family:Cambria;font-size:17px;\">record of number of dependants per employee </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is the record of numbers of hours worked. Recall that a source document is the original record containing the details to substantiate a transaction entered in an accounting system. For example, a company's source document for the recording of merchandise purchased is the supplier's invoice supported by the company's purchase order and receiving ticket.</div>", "topic": "INTRODUCTION TO ACCOUNTING : MEANING AND OBJECTIVES OF ACCOUNTING AND BOOKKEEPING"}, {"id": "objective>Accounts>2013>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following items is a capital expenditure? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">maintenance of office machine </div>", "<div style=\"font-family:Cambria;font-size:17px;\">purchase of office stationery </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Carriage inwards </div>", "<div style=\"font-family:Cambria;font-size:17px;\">purchase of office machinery </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Purchase of office machinery is a capital expenditure. A capital expenditure is incurred when a business spends money either to buy fixed assets or to add to the value of an existing fixed asset with a useful life extending beyond the taxable year.</div>", "topic": "THE JOURNAL : MEANING AND USES OF JOURNAL"}, {"id": "objective>Accounts>2013>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The corresponding entry of personal accounts found in the debit side of the cash book is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">credit real accounts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">debit real accounts </div>", "<div style=\"font-family:Cambria;font-size:17px;\">credit the ledger </div>", "<div style=\"font-family:Cambria;font-size:17px;\">debit the ledger </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The principle of contra entry states that for every debit entry, there must be a corresponding credit entry</div>", "topic": "CASH BOOK : MEANING AND TYPES OF CASH BOOK"}, {"id": "objective>Accounts>2013>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Alaka who owed Saka ₦15,000, settled his debt after deducting cash discount of 10%. To record the discount in the book of Saka, debit</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">discount received account and credit Alaka's account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Alaka's account and credit discount received account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Saka's account and credit discount received account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">discount allowed account and credit Alaka's account </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When Alaka settles his debt after deducting a cash discount, Saka will record the discount as 'discount received'. This is because from Saka's perspective, the discount is an income or gain. Therefore, Saka will debit the 'discount received account' (increasing his income) and credit Alaka's account (decreasing his debtor's balance). This follows the rule of 'Debit the receiver, Credit the giver' in accounting.</div>", "topic": "RESERVES AND PROVISIONS : PROVISION FOR DISCOUNTS ALLOWED AND RECEIVED"}, {"id": "objective>Accounts>2013>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. The amount of the imprest is the same from one organization to another <br/>  <br/>  II. At the end of a fixed period, the petty cashier is reimbursed with the amount spend in that period  <br/>  III. At the end of a period, the petty cashier is reimbursed with the amount spend in that period  <br/>  IV. The system is a method by which a measure of control is kept on petty cash expenses.  <br/> Which of the above is correct about the imprest system?    </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I, II and III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III and IV</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Imprest system is a system for recording petty cash transactions, which are paid out of cash float. The system is set up by giving a specified sum known as cash float to the cashier to cover petty expenses during the period. The petty cashier will pay out money from the float for all authorized vouchers. At frequent intervals, he will be re-imbursed for the amount spent thus bringing it to the original amount.</div>", "topic": "PETTY CASH BOOK : MEANING AND IMPORTANCE"}, {"id": "objective>Accounts>2013>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the information below to answer this question.  <br/>  A machine bought for ₦35,000 was estimated to have a life span of 5 years with a scrap value of ₦9,000. <br/>  <br/> The yearly depreciation using the straight line method would be </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦8,800</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦6,500</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦5,200</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦4,400 </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Depreciation per year = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">Purchase cost - scrap value</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">useful life</span> <br/>   <br/>  = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">35,000 - 9,000</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">5 </span> <br/>  <br/> = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">26,000</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">5</span> <br/>  <br/>  = ₦5,200.</div>", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION"}, {"id": "objective>Accounts>2013>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the information below to answer this question.  <br/>  A machine bought for ₦35,000 was estimated to have a life span of 5 years with a scrap value of ₦9,000.  <br/> If the scrap value is presently ₦15,000, what will be the yearly depreciation using straight line method?  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦4,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦7,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦11,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦24,000 </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Depreciation per year = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">purchase cost - scrap value</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">useful life</span>  <br/>  <br/>  = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">35,000 - 15,000</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">5 </span> <br/>  <br/> = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">20,000</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">5 </span> <br/>  <br/> = ₦4,000.</div>", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION"}, {"id": "objective>Accounts>2013>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The purchase of mattresses from Freehold Enterprises by cheque amounted to ₦305,150. The correct entries for this transaction in the book of the buyer is to debit  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sales account and credit bank account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">purchases and credit bank account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cash and credit freehold </div>", "<div style=\"font-family:Cambria;font-size:17px;\">bank and credit freehold </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a company purchases an item, it debits (increases) its Purchases account. Since the purchase was made by cheque, the company also credits (decreases) its Bank account. Therefore, the correct entries for this transaction in the book of the buyer is to debit Purchases account and credit Bank account.</div>", "topic": "THE JOURNAL : MEANING AND USES OF JOURNAL"}, {"id": "objective>Accounts>2013>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the information below to answer this question. <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Sales</td><td style=\"border:1px solid black;text-align:center;\"> ₦232,000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Opening stock</td><td style=\"border:1px solid black;text-align:center;\"> ₦28,000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Purchases </td><td style=\"border:1px solid black;text-align:center;\"> ₦128,000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Carriage in wards </td><td style=\"border:1px solid black;text-align:center;\"> ₦4,000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Carriage outwards </td><td style=\"border:1px solid black;text-align:center;\"> ₦6,000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Closing stock </td><td style=\"border:1px solid black;text-align:center;\"> ₦10,000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Discount received </td><td style=\"border:1px solid black;text-align:center;\"> ₦18,000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Expenses </td><td style=\"border:1px solid black;text-align:center;\"> ₦20,000</td></tr></table></div> <br/>  <br/> Calculate the gross profit </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦100,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦86,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦82,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦76,000</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gross profit = Sales - Cost of sales(purchases + discount + carriage inwards/ cost of transport to purchase goods)  <br/>  = ₦ 232,000 - ₦(128,000 + 18,000 + 4,000) = ₦232,000 - ₦150,000  <br/>  = ₦82,000.</div>", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES"}, {"id": "objective>Accounts>2013>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the information below to answer this question. <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Sales</td><td style=\"border:1px solid black;text-align:center;\"> ₦232,000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Opening stock</td><td style=\"border:1px solid black;text-align:center;\"> ₦28,000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Purchases </td><td style=\"border:1px solid black;text-align:center;\"> ₦128,000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Carriage in wards </td><td style=\"border:1px solid black;text-align:center;\"> ₦4,000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Carriage outwards </td><td style=\"border:1px solid black;text-align:center;\"> ₦6,000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Closing stock </td><td style=\"border:1px solid black;text-align:center;\"> ₦10,000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Discount received </td><td style=\"border:1px solid black;text-align:center;\"> ₦18,000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Expenses </td><td style=\"border:1px solid black;text-align:center;\"> ₦20,000</td></tr></table></div> <br/> Calculate the expenses debited to the profit and loss account </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦17,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦23,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦26,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦30,000 </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The expenses debited to the profit and loss account are the expenses that are directly related to the business operations. <br/>  <br/>  In this case, the expenses are the carriage outwards and the expenses, which total to ₦6,000 + ₦20,000  <br/> = ₦26,000.</div>", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT"}, {"id": "objective>Accounts>2013>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Opening capital</td><td style=\"border:1px solid black;text-align:center;\">₦1 500 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Capital introduced</td><td style=\"border:1px solid black;text-align:center;\">₦500 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Profit for the year </td><td style=\"border:1px solid black;text-align:center;\">₦800 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Cash drawings</td><td style=\"border:1px solid black;text-align:center;\">₦250</td></tr></table></div> <br/> Calculate the closing capital. </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦2,550</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦2,500 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦2350 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦2,250</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">NP = CC +D - OC + AD <br/>  <br/> where: NP = Net profit,   CC = Closing capital,  D = Drawings,  OC = Opening capital  , AC = Additional capital <br/>  <br/>                        800   = CC + 250 - (1500+500) <br/>                            800  = CC + 250 - 2000 <br/>                           CC = 800 - 250 + 2000 <br/>                                     CC = 2550</div>", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION"}, {"id": "objective>Accounts>2013>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What type of stock valuation method would a vegetable seller adopt in valuing its product? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">LIFO</div>", "<div style=\"font-family:Cambria;font-size:17px;\">FIFO</div>", "<div style=\"font-family:Cambria;font-size:17px;\">simple interest </div>", "<div style=\"font-family:Cambria;font-size:17px;\">weight average </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">FIFO means First-In, First-Out. FIFO is a coherent method for it takes into consideration the normal procedure of utilizing the first received materials being used first. Materials are issued in the order of purchases, and thus the materials used first are utilized first. Since Vegetable is perishable, this method will therefore suit.</div>", "topic": "STOCK VALUATION : MEANING OF STOCK VALUATION AND METHODS"}, {"id": "objective>Accounts>2013>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The total cash and cheque received from customers in a control account is derived from the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">purchase day book </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cash book </div>", "<div style=\"font-family:Cambria;font-size:17px;\">income and expenditure account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sales journal </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The total cash and cheque received from customers in a control account is derived from the cash book. The cash book is a financial journal that contains all cash receipts and payments, including bank deposits and withdrawals. Entries in the cash book are then posted into the general ledger.</div>", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT"}, {"id": "objective>Accounts>2013>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the information below to answer this question. <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">  </td><td style=\"border:1px solid black;text-align:center;\"> 1/1/2010</td><td style=\"border:1px solid black;text-align:center;\">  </td><td style=\"border:1px solid black;text-align:center;\"> 31/12/2010 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> ₦</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> ₦ <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Creditors</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> 9 000</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> 9 800 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Rent owing</td><td style=\"border:1px solid black;text-align:center;\"> 3 800</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> 2 500</td><td style=\"border:1px solid black;text-align:center;\">  <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Rate prepaid</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\">  2 000</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> 3 500 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Motor van</td><td style=\"border:1px solid black;text-align:center;\"> 8 000</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> 8 000</td><td style=\"border:1px solid black;text-align:center;\">  <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Premises</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> 10 500</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> 10 500</td></tr></table></div> <br/>  <br/> Find the opening capital </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦5,700</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦7,700</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦9,800</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦14,900</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Opening capital = opening assets - opening liabilities  <br/> = ₦(2,000 + 8,000 + 10,500) - ₦(9,000 + 3,800)  <br/>  = ₦(20,500 - 12,800)  <br/>  = ₦7,700.</div>", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION"}, {"id": "objective>Accounts>2013>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the information below to answer this question. <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">  </td><td style=\"border:1px solid black;text-align:center;\"> 1/1/2010</td><td style=\"border:1px solid black;text-align:center;\">  </td><td style=\"border:1px solid black;text-align:center;\"> 31/12/2010 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> ₦</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> ₦ <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Creditors</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> 9 000</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> 9 800 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Rent owing</td><td style=\"border:1px solid black;text-align:center;\"> 3 800</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> 2 500</td><td style=\"border:1px solid black;text-align:center;\">  <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Rate prepaid</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\">  2 000</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> 3 500 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Motor van</td><td style=\"border:1px solid black;text-align:center;\"> 8 000</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> 8 000</td><td style=\"border:1px solid black;text-align:center;\">  <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Premises</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> 10 500</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> 10 500</td></tr></table></div> <br/> Calculate the value of closing capital </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦8,700</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦9,500</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦9,700</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦10,700</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Closing capital = closing assets - closing liabilities  <br/> = ₦(3,500 + 8,000 + 10,500) - ₦(9,800 + 2,500)  <br/>  = ₦(22,000 - 12,300)  <br/>  = ₦9,700.</div>", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION"}, {"id": "objective>Accounts>2013>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Opening Capital</td><td style=\"border:1px solid black;text-align:center;\">₦50,000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Closing Capital</td><td style=\"border:1px solid black;text-align:center;\">₦64,000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Drawings</td><td style=\"border:1px solid black;text-align:center;\">₦16,000</td></tr></table></div> <br/> Determine the net profit </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦2,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦14,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦20,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦30,000 </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Net profit = Closing capital +Drawings - Closing capital <br/>                               = 64000 +16000 - 50000 <br/>                                         = 30,000</div>", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION"}, {"id": "objective>Accounts>2013>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The estimate profit or loss for a period is calculated by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">closing capital less opening capital add drawings</div>", "<div style=\"font-family:Cambria;font-size:17px;\">opening capital less closing capital add drawings</div>", "<div style=\"font-family:Cambria;font-size:17px;\">opening capital less drawings add closing capital </div>", "<div style=\"font-family:Cambria;font-size:17px;\">opening capital add closing capital add drawings</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The estimated profit or loss for a period is calculated by subtracting the opening capital from the closing capital and adding any drawings. This is because the closing capital represents the total value of the business at the end of the period, while the opening capital represents the total value at the beginning. Drawings are amounts taken out of the business by the owner, which reduce the capital.  <br/>  <br/> Therefore, the formula is: Profit or Loss = Closing Capital - Opening Capital + Drawings.</div>", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION"}, {"id": "objective>Accounts>2013>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If Mr. Ajasin paid his creditors ₦5,000 out of ₦20,000 owed, what would be the effect of this transaction on the accounting equation?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a decrease in the total liabilities and assets by ₦5,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">An increase in total liabilities and owners' equity by ₦15,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">An increase in the total assets by ₦15,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A decrease in owners equity by ₦5,000</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A decrease in the total liabilities and assets by ₦5,000. He will debit total liabilities and credit cash.</div>", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION"}, {"id": "objective>Accounts>2013>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When goods produced are transferred at cost plus mark-up before sale, the difference between the cost and the transferred price is a  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">discount </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sales commission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">manufacturing profit </div>", "<div style=\"font-family:Cambria;font-size:17px;\">factory reserves</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The difference gives the manufacturing profit.  <br/>  <br/> Manufacturing profit =  price for transferred good - cost.</div>", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE"}, {"id": "objective>Accounts>2013>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The addition of the prime cost, indirect cost and opening work-in-progress less the closing work-in-progress will result in cost of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">goods available for sale</div>", "<div style=\"font-family:Cambria;font-size:17px;\">goods sold </div>", "<div style=\"font-family:Cambria;font-size:17px;\">goods manufactured </div>", "<div style=\"font-family:Cambria;font-size:17px;\">materials put into production </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Maufacturing account is prepared to ascertain the cost of goods manufactured during the financial year.</div>", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE"}, {"id": "objective>Accounts>2013>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the information below to answer this question <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Opening stock of raw materials </td><td style=\"border:1px solid black;text-align:center;\"> ₦75,000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Purchase of raw materials </td><td style=\"border:1px solid black;text-align:center;\"> ₦330,000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Closing stock of raw materials </td><td style=\"border:1px solid black;text-align:center;\">₦80,000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Direct wages </td><td style=\"border:1px solid black;text-align:center;\"> ₦30,000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Carriage of raw materials </td><td style=\"border:1px solid black;text-align:center;\">₦10,000</td></tr></table></div> <br/>  <br/> Calculate the cost of raw materials used </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦495,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦415,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦335,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦305,000</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cost of raw materials used = opening stock + purchases - closing stock + carriage of raw materials  <br/>  = ₦(75,000 + 330,000 - 80,000 + 10,000)  <br/> = ₦335,000.</div>", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE"}, {"id": "objective>Accounts>2013>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the information below to answer this question <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Opening stock of raw materials </td><td style=\"border:1px solid black;text-align:center;\"> ₦75,000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Purchase of raw materials </td><td style=\"border:1px solid black;text-align:center;\"> ₦330,000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Closing stock of raw materials </td><td style=\"border:1px solid black;text-align:center;\">₦80,000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Direct wages </td><td style=\"border:1px solid black;text-align:center;\"> ₦30,000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Carriage of raw materials </td><td style=\"border:1px solid black;text-align:center;\">₦10,000</td></tr></table></div> <br/> Determine the prime cost </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦525,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦515,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦465,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦365,000</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The prime cost is calculated by adding the cost of raw materials used (which we calculated in the first question) to the direct wages and the carriage of raw materials.  <br/>  <br/> This gives: ₦325,000 + ₦30,000 + ₦10,000  <br/> = ₦365,000. </div>", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE"}, {"id": "objective>Accounts>2013>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a manufacturing account, the work-in-progress at the end of the year is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">deducted from the cost of goods completed during the year </div>", "<div style=\"font-family:Cambria;font-size:17px;\">added to the cost of goods completed  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">stated in the profit and loss accost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stated in the prime cost section</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Goods which are not finished are known as work-in-progress. The opening balance of work-in-progress is added on to the production cost and the work-in-progress left at the end of the year will need subtracting to give us the cost of the goods completed during the period we are dealing with.</div>", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE"}, {"id": "objective>Accounts>2013>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is accounted for in receipts and payments account</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Subscription received in advance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Subscription due not yet received </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Accrued expenses on annual dances </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Depreciation of the club house </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A receipts and payments account is a summary of actual cash receipts and payments extracted from the cash book over a certain period. All cash received and paid during the period whether capital or revenue is included in this account. It contains Subscriptions received in advance</div>", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : RECEIPTS AND PAYMENTS ACCOUNTS"}, {"id": "objective>Accounts>2013>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following expenses relates to the profit and loss account of a manufacturing firm? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Direct materials</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Direct labour </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Administrative overhead</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Work-in-progress </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Administrative overhead is those costs not involved in the development or production of goods or services. This is essentially all overhead that is not included in manufacturing overhead. Examples of administrative overhead costs are the costs of: Front office and sales salaries, wages, and commissions, Office supplies</div>", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE"}, {"id": "objective>Accounts>2013>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. Direct materials  <br/> II. Direct labour  <br/> III. Direct expenses  <br/> IV. Factory expenses. <br/>  Prime cost consist of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I, II and III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, III and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II, III, IV </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Prime cost is the direct cost of a commodity in terms of the materials and labour involved in its production, excluding fixed costs. Direct material and direct labor costs are prime cost because they are the main incremental costs of a product.</div>", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE"}, {"id": "objective>Accounts>2013>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The amount paid by the new partner on admission as a compensation for the reputation built up by old partners is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bonus </div>", "<div style=\"font-family:Cambria;font-size:17px;\">commission </div>", "<div style=\"font-family:Cambria;font-size:17px;\">premium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">goodwill </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> Goodwill is an intangible asset that arises when a buyer acquires an existing business or a partner joins an existing partnership.</div>", "topic": "GOODWILL ACCOUNTS : INTRODUCTION AND REASONS FOR GOODWILL"}, {"id": "objective>Accounts>2013>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A partnership's internal regulations are set out by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a deed </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a law </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a constitution </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an article </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A deed or partnership deed is  a document containing an agreement that details the rights and obligations of each partner participating in a venture.</div>", "topic": "PARTNERSHIP ACCOUNT : INTRODUCTION AND TYPES OF PARTNERS( PARTNERSHIP)"}, {"id": "objective>Accounts>2013>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a partnership account, interest on drawing is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">debited to appropriation account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">credited to appropriation account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">treated as an expense in profit and loss account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">record in the balance sheet as current assets </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is credited to appropriation account. The appropriation account is an account showing what has been done with the total funds available to a company or other organisation.</div>", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR"}, {"id": "objective>Accounts>2013>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a share valued at 50k is issued at ₦1.50, it is said to be issued at</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">par</div>", "<div style=\"font-family:Cambria;font-size:17px;\">premium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">discount </div>", "<div style=\"font-family:Cambria;font-size:17px;\">interest </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Issue of shares at premium means that the issuing of shares above the face value (also called as nominal value or par value). Simply put, when shares are issued at a price higher than the face value, it is said to be issued at a premium.</div>", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES"}, {"id": "objective>Accounts>2013>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The purchase consideration that is lower than the net asset implies that, the buyer has gained the advantage of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">net income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">revenue reserve </div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital reserve </div>", "<div style=\"font-family:Cambria;font-size:17px;\">net loss </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Capital reserve is the excess of identifiable assets or net value of assets over the purchase consideration. The difference will be posted to the capital reserve account.</div>", "topic": "PURCHASES OF BUSINESS : INTRODUCTION AND ADVANTAGES"}, {"id": "objective>Accounts>2013>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When shares are issued at a discount, the entries are to debit </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">application and allotment account and debit discount account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">discount account and credit application and allotment account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cash account and credit discount </div>", "<div style=\"font-family:Cambria;font-size:17px;\">discount account and credit bank account </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Issue of shares at discount accounting entries are: <br/> - On receipt of application money: Dr Bank account and CR Application and Allotment account <br/> - On allotment: Dr Application and Allotment account, Dr discount account and Cr Ordinary share capital account </div>", "topic": "ISSUES OF SHARES : SHARES ISSUED PAYABLE BY INSTALMENTS"}, {"id": "objective>Accounts>2013>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When there is no basis of apportionment in an organization, the expenses should be apportioned based on </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sales </div>", "<div style=\"font-family:Cambria;font-size:17px;\">purchases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">equality </div>", "<div style=\"font-family:Cambria;font-size:17px;\">floor space </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When there is no specific basis of apportionment in an organization, the expenses should be apportioned based on equality. This means that the expenses are divided equally among the departments or cost centers. This method is used when there is no clear or logical basis for apportioning the costs.</div>", "topic": "DEPARTMENTAL ACCOUNT : METHODS OF APPORTIONMENT OF EXPENSES"}, {"id": "objective>Accounts>2013>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the information below to answer this question. <br/>  <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Department</td><td style=\"border:1px solid black;text-align:center;\"> K</td><td style=\"border:1px solid black;text-align:center;\">   Y <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> ₦</td><td style=\"border:1px solid black;text-align:center;\">  ₦ <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Opening stock</td><td style=\"border:1px solid black;text-align:center;\"> 2 500</td><td style=\"border:1px solid black;text-align:center;\">  800 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Purchases</td><td style=\"border:1px solid black;text-align:center;\"> 120 000</td><td style=\"border:1px solid black;text-align:center;\">  100 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Sales</td><td style=\"border:1px solid black;text-align:center;\"> 180 000</td><td style=\"border:1px solid black;text-align:center;\">  200 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Salaries</td><td style=\"border:1px solid black;text-align:center;\">  8 000</td><td style=\"border:1px solid black;text-align:center;\"> 30 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Closing stock</td><td style=\"border:1px solid black;text-align:center;\">  3 000</td><td style=\"border:1px solid black;text-align:center;\"> 1 500</td></tr></table></div> <br/> Rate expenses are of ₦1,500 are apportioned in the ratio 1:2 <br/>  <br/> The gross profit for K is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦23,500</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦60,500</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦60,700</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦82,500 </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gross profit = Sales - Cost of goods(opening stock + purchases - closing stock)  <br/> = ₦(180,000 - [ 2500 + 120000 - 3000])  <br/> = ₦60,500.</div>", "topic": "DEPARTMENTAL ACCOUNT : PRESENTATION OF FINAL ACCOUNTS"}, {"id": "objective>Accounts>2013>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the information below to answer this question. <br/>  <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Department</td><td style=\"border:1px solid black;text-align:center;\"> K</td><td style=\"border:1px solid black;text-align:center;\">   Y <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> ₦</td><td style=\"border:1px solid black;text-align:center;\">  ₦ <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Opening stock</td><td style=\"border:1px solid black;text-align:center;\"> 2 500</td><td style=\"border:1px solid black;text-align:center;\">  800 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Purchases</td><td style=\"border:1px solid black;text-align:center;\"> 120 000</td><td style=\"border:1px solid black;text-align:center;\">  100 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Sales</td><td style=\"border:1px solid black;text-align:center;\"> 180 000</td><td style=\"border:1px solid black;text-align:center;\">  200 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Salaries</td><td style=\"border:1px solid black;text-align:center;\">  8 000</td><td style=\"border:1px solid black;text-align:center;\"> 30 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Closing stock</td><td style=\"border:1px solid black;text-align:center;\">  3 000</td><td style=\"border:1px solid black;text-align:center;\"> 1 500</td></tr></table></div> <br/> Rate expenses are of ₦1,500 are apportioned in the ratio 1:2 <br/> What is the net profit of Y?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦52,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦68,300</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦68,800</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦69,700</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Net profit = Gross profit - Expenses <br/> Total ratio = 1+2 = 3 <br/>  <br/> Gross profit = Sales - Cost of goods(Opening stock + Purchases - Closing stock ) - salaries - expenses  <br/>                                     =   200,000 - [800 + 100,000 - 1500)  <br/>                                                   GP = 100,700 <br/>  <br/> Expenses  = Salaries + Rate ( 2/3 x 1500) <br/>                         = 30,000  + 1000 = 31,000 <br/>                                       NP = 100,700 - 31,000 <br/>                                                            = 69,700</div>", "topic": "DEPARTMENTAL ACCOUNT : PRESENTATION OF FINAL ACCOUNTS"}, {"id": "objective>Accounts>2013>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The objective of departmental account is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ascertain the cost of running th organization </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ascertain the amount of profit or loss for each department</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ascertain the amount of profits or losses for the enterprise</div>", "<div style=\"font-family:Cambria;font-size:17px;\">offset the loss of each department </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Some primary objectives of departmental accounting are as follows: To compare the performance of each department with their previous year performance as well as with the other departments of the organization to measure the efficiency of the departments.</div>", "topic": "DEPARTMENTAL ACCOUNT : INTRODUCTION AND ADVANTAGES OF DEPARTMENTAL ACCOUNT"}, {"id": "objective>Accounts>2013>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is the capital reserve of a company?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">share premium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Retained profit </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Accumulated depreciation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Loss on forfeited shares</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A capital reserve is an account in the equity section of the balance sheet that can be used for contingencies or to offset capital losses. It is derived from the accumulated capital surplus of a company, created out of capital profit. <br/>  <br/> Capital Reserve is a type of profit that is earned on capital transactions - an example would be the profit arising from the forfeiture of shares, share premium, Capital Redemption Reserve or Debenture Redemption Reserve.</div>", "topic": "COMPANY ACCOUNT : INTRODUCTION , TYPES AND KINDS OF COMPANIES"}, {"id": "objective>Accounts>2013>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> Application were invited by the director of Abiodun PLC for 500,000 ordinary shares of ₦1:00 each at ₦1:10 per share payable as follows: <br/> On application------- 46k  <br/>  On allotment -------- 20k <br/>  1st call ------------ 15k  <br/>   2nd call ----------- 19k  <br/>  How much is to be paid for application? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦230,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦280,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦500,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦550,000</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The question states that applications were invited for 500,000 ordinary shares at ₦1:10 per share, and the amount payable on application is 46k (₦0.46).  <br/>  <br/> Therefore, the total amount to be paid for application is 500,000 shares x ₦0.46  <br/> = ₦230,000.</div>", "topic": "ISSUES OF SHARES : SHARES ISSUED PAYABLE BY INSTALMENTS"}, {"id": "objective>Accounts>2013>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The issued share capital is the number of shares that are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">authorised by the shareholders  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">shares among the directors </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fully subscribed </div>", "<div style=\"font-family:Cambria;font-size:17px;\">in the share certificate </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The issued share capital refers to the total value of shares that a company has issued to shareholders. It is not necessarily the total number of authorized shares that a company can issue, nor is it the shares among the directors or in the share certificate. </div>", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES"}, {"id": "objective>Accounts>2013>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The distributable profit available to shareholders at the end of each year are the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">total profit and debtors balance </div>", "<div style=\"font-family:Cambria;font-size:17px;\">general reserve and retained profit </div>", "<div style=\"font-family:Cambria;font-size:17px;\">retained profit and fictitious assets </div>", "<div style=\"font-family:Cambria;font-size:17px;\">total profit less creditors' balance </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The distributable profit available to shareholders at the end of each year is the amount of earnings that is available to be distributed as dividends to shareholders. This is typically calculated as the total profit less any amounts that the company wishes to retain for future investment or to cover future losses. </div>", "topic": "RESERVES AND PROVISIONS : MEANING OF RESERVE AND PROVISIONS"}, {"id": "objective>Accounts>2013>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The debenture issued at par above the nominal value is said to be issued at a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cost price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mark-up</div>", "<div style=\"font-family:Cambria;font-size:17px;\">premium </div>", "<div style=\"font-family:Cambria;font-size:17px;\">margin </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Issues of shares at premium is a situation whereby shares are quoted above the nominal value i.e the issue price is greater than the nominal value.</div>", "topic": "ISSUES OF SHARES : CALLS IN ARREARS AND FORFEITURE OF SHARES"}, {"id": "objective>Accounts>2013>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Accountant-General of the federation is responsible for </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the general supervision of all auditing personnel in all the ministries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the compilation of annual financial statement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the interpretation of rules and regulations affecting the private sectors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ensuring the efficient operation of the ministry </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The compilation of annual financial statement is the responsibility of the Accountant-General. He is also responsible for the overall management of all receipt and payments of the Federal Republic of Nigeria.</div>", "topic": "PUBLIC SECTOR ACCOUNTING : INTRODUCTION AND USERS OF GOVERNMENT ACCOUNTING"}, {"id": "objective>Accounts>2013>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> Assets and Liability of a local Government <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Bank balance</td><td style=\"border:1px solid black;text-align:center;\">₦6,484,000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Cash</td><td style=\"border:1px solid black;text-align:center;\">₦900,000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">General revenue balances</td><td style=\"border:1px solid black;text-align:center;\">₦9,774 500 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Accrued salaries</td><td style=\"border:1px solid black;text-align:center;\">₦1,220 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Investments in shares</td><td style=\"border:1px solid black;text-align:center;\">₦1,480,000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Vehicles</td><td style=\"border:1px solid black;text-align:center;\">₦7,620,000</td></tr></table></div> <br/> Calculate the liabilities of the local government</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦10,994,500</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦17,394,500</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦18,774,500</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦18,874,500</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">liabilities = accrued salaries + general revenue balances  <br/> = ₦(1,220 000 + 9,774 500)  <br/> = ₦10,994,500</div>", "topic": "PUBLIC SECTOR ACCOUNTING : SOURCES AND CLASSIFICATION OF GOVERNMENT REVENUE"}, {"id": "objective>Accounts>2013>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An instrument which allows public officers to increase expenditure within a year is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">statutory allocation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">supplementary budget </div>", "<div style=\"font-family:Cambria;font-size:17px;\">virement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">warrant </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Supplementary budget is the additional estimate as a result of short falls in the main budget.  It must be given approval by the legislature.</div>", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES"}];
